function [cntX2,cntY2,rotAngl] = fImgCntAnglV02(img,angle,threshold,vargin)%% analyze image to get centroid and rotation angle% [cntX2,cntY2,rotAngl] = fImgCntAnglV02(img,threshold,vargin)% cntX, cntY: centroid [pixel]% rotAngl: rotation angle [deg]% % img: input image% threshold: threshold% vergin: if any, putput figure%% Written by Kei Nakamura% 2016/1/6 ver.1: created% 2016/1/6 ver.2: output centroid and angle%% get centroidimg = img.*(img>threshold);  % thresholding[sizeY,sizeX] = size(img);  % image sizexPrf = sum(img);    % x profile, integrated in yyPrf = sum(img,2);  % y profile, integrated in x[~,cntX] = fGetRmsV01(1:sizeX,xPrf);  % centroid x[~,cntY] = fGetRmsV01(1:sizeY,yPrf');  % centroid ycntX = round(cntX); cntY = round(cntY);%% rotation scan to seerotImg = img;   % allocationxStd = angle;   % allocationyStd = angle;   % allocationpeakP = angle;   % allocationdiffLR = angle; % allocationfor ii=1:numel(angle)    rotImg(:,:) = fImageRotV02(img,angle(ii),[cntX,cntY]);    [rotImg(:,:),diffLR(ii)] = fImageSymV01(rotImg);   % symmetrize    rotImgX = sum(rotImg);  % x profile    rotImgY = sum(rotImg,2);  % x profile    [xStd(ii),~] = fGetRmsV01(1:sizeX,rotImgX);  % x-rms    [yStd(ii),~] = fGetRmsV01(1:sizeY,rotImgY');  % y-rms    peakP(ii) = max(rotImgX);end%% define angle based on min(diffLR)[~,rotAnglInd] = min(diffLR);   % indexrotAngl = angle(rotAnglInd);    % rotation angle [deg]lin1 = fPa2Line([cntX cntY],tan(rotAngl*pi/180));lin2 = fPa2Line([cntX cntY],-tan((90-rotAngl)*pi/180));%% get new image and # forimg2 = fImageRotV02(img,rotAngl,[cntX,cntY]);xPrf2 = sum(img2);    % x profile, integrated in yyPrf2 = sum(img2,2);  % y profile, integrated in x[~,cntX2] = fGetRmsV01(1:sizeX,xPrf2);  % centroid x[~,cntY2] = fGetRmsV01(1:sizeY,yPrf2');  % centroid ycntX2 = round(cntX2); cntY2 = round(cntY2);if nargin>3    %subplot(1,4,1)    set(gca,'fontsize',14);    pcolor(img)    shading interp    colormap jet    hold on    plot([1 sizeX],[fLineX2YV01(lin1,1) fLineX2YV01(lin1,sizeX)],'w-')    plot([1 sizeX],[fLineX2YV01(lin2,1) fLineX2YV01(lin2,sizeX)],'w-')    hold off    %caxis([0 2])    colorbar    title('original image')    axis([cntX2-100 cntX2+100 cntY2-100 cntY2+100])    set(gca,'fontsize',14);end%%% figure(100)% % subplot(1,4,1)% set(gca,'fontsize',14);% %pcolor(log10(img))% pcolor(img)% shading interp% colormap jet% hold on% plot([1 sizeX],[fLineX2YV01(lin1,1) fLineX2YV01(lin1,sizeX)],'w-')% plot([1 sizeX],[fLineX2YV01(lin2,1) fLineX2YV01(lin2,sizeX)],'w-')% hold off% %caxis([0 2])% colorbar% title('original image')% axis([250 430 300 520])% set(gca,'fontsize',14);% % subplot(1,4,2)% set(gca,'fontsize',14);% %img3(:,:) = fImageSymV01(img3);   % symmetrize% %pcolor(log10(img3))% pcolor(img2)% shading interp% hold on% plot([1 sizeX],[cntY2 cntY2],'w-')% plot([cntX2 cntX2],[1 sizeY],'w-')% hold off% %caxis([0 2])% colorbar% title([num2str(rotAngl,3) ' deg'])% axis([250 430 300 520])% set(gca,'fontsize',14);% % subplot(1,4,3)% set(gca,'fontsize',14);% plotyy(angle,xStd,angle,yStd)% title('blue:xStd, red:yStd')% xlabel('rotation angle')% ylabel('std')% set(gca,'fontsize',14);% % subplot(1,4,4)% set(gca,'fontsize',14);% plotyy(angle,peakP,angle,diffLR)% title('blue:peakP, red:diffLR')% xlabel('rotation angle')% ylabel('std')% set(gca,'fontsize',14);%%% figure(101)% subplot(1,2,1)% pcolor(img)% shading interp% hold on% plot([1 sizeX],[cntY cntY],'w-')% plot([cntX cntX],[1 sizeY],'w-')% hold off% %caxis([0 2])% axis([150 500 200 600])% colorbar% % subplot(1,2,2)% pcolor(img2)% shading interp% hold on% plot([1 sizeX],[cntY cntY],'w-')% plot([cntX cntX],[1 sizeY],'w-')% hold off% axis([150 500 200 600])% %caxis([0 2])% colorbar
